#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long ans = X * 10 + Y * 5;
        printf("%lld\n", ans);
    }
    return 0;
}

